  # SSE output from a single stdio MCP process crashes when multiple clients
  # connect concurrently. Use stateful Streamable HTTP for stdio MCP servers
  # shared by Codex, Claude, Gemini, nvim, and other clients.
  streamableHttpArgs = [
    "--outputTransport"
