        RUN ln -s /usr/local/lib/node_modules/supergateway/dist/index.js /usr/local/bin/supergateway && chmod +x /usr/local/bin/supergateway
        COPY --from=github /server/github-mcp-server /usr/local/bin/github-mcp-server
