      };
    };

    kagisearch = {
      port = 3018;
      internalPort = 8000;
      mcpPath = streamableHttpPath;
      dockerfile = ''
        FROM node:22-alpine
        RUN npm install -g supergateway
        WORKDIR /app
      '';
      command = [
        "supergateway"
        "--stdio"
        "npx -y kagi-mcp"
        "--port"
        "8000"
      ]
      ++ streamableHttpArgs;
      env = {
        KAGI_SUMMARIZER_ENGINE = "\${KAGI_ENGINE}";
